const crypto = require('crypto');

/**
 * Generate a unique voter fingerprint.
 * 
 * Uses a custom header 'x-voter-id' if provided (for browser-based uniqueness),
 * otherwise falls back to IP + User-Agent hash.
 * 
 * The frontend generates a random ID stored in localStorage so each
 * browser tab/profile gets a unique fingerprint, enabling proper testing
 * on the same machine with different browser profiles.
 */
function generateFingerprint(req) {
  // Check for custom voter ID header (generated by frontend per browser)
  const voterId = req.headers['x-voter-id'];
  if (voterId) {
    return crypto.createHash('sha256').update(voterId).digest('hex');
  }

  // Fallback: IP + User-Agent
  const ip = req.ip || req.headers['x-forwarded-for'] || req.connection.remoteAddress;
  const userAgent = req.headers['user-agent'] || '';

  const raw = `${ip}::${userAgent}`;
  return crypto.createHash('sha256').update(raw).digest('hex');
}

module.exports = generateFingerprint;
